SELECT flag_name, government_type
FROM flag_states
WHERE government_type = 'Presidential republic';

SELECT government_type, AVG(population) AS average_population
FROM flag_states
GROUP BY government_type;

SELECT flag_name
FROM flag_states
WHERE population = (SELECT MAX(population) FROM flag_states);

SELECT COUNT(flag_state_id) AS number_of_flag_states
FROM flag_states
WHERE region = 'Europe';

SELECT flag_name, population, gdp
FROM flag_states
WHERE flag_state_id = 1;

SELECT vessel_name, inspection_date, inspection_type
FROM inspections
WHERE inspection_id = 1;
